-- ════════════════════════════════════════════════════════════════════════════
-- Showbiz Elite Show Choir — Disneyland & Universal Studios (Jun 14-20, 2026)
-- Tour Host: Linda Deming (efbf888c-5348-4071-b720-961e2795698c)
-- Run this in the Supabase SQL Editor.
--
-- All IDs use gen_random_uuid() (the column default). A DO block captures the
-- generated tour/day IDs so agenda rows can reference their parents.
-- Re-runnable: deletes the tour by name first; FK cascade clears its days,
-- items, and post_trip record.
-- ════════════════════════════════════════════════════════════════════════════

DO $$
DECLARE
  v_tour uuid;
  d1 uuid; d2 uuid; d3 uuid; d4 uuid; d5 uuid; d6 uuid; d7 uuid;
BEGIN

  -- ─── Safety: remove prior copy (cascade clears days/items/post_trip) ────────
  DELETE FROM tours WHERE name = 'Showbiz Elite Show Choir - Disneyland & Universal Studios';

  -- ─── Tour ───────────────────────────────────────────────────────────────────
    tour_host_id, name, school, contact_name, contact_email,
    destination, dates, start_date, end_date,
    status, transport_type, bus_capacity, student_count, notes, access_codes
  ) VALUES (
    'efbf888c-5348-4071-b720-961e2795698c',
    'Showbiz Elite Show Choir - Disneyland & Universal Studios',
    'Showbiz Elite Show Choir',
    'Taneil Serr',
    'taneilserr@gmail.com',
    'Anaheim, CA',
    'Jun 14-20, 2026',
    '2026-06-14',
    '2026-06-20',
    'committed',
    'bus',
    56,
    26,
    'Holiday Motor Coach LLC, 56 passenger. Hotel: Anaheim Suites Hotel, 101 E Katella Ave, Anaheim CA 92802 (3 Bunk Suites, 8 Double Queen Rooms, 2 Double Queen with Sofa). 40 total participants: 26 performing students, 13 chaperones, 1 tour host.',
    '{"coordinator":"SHOWBIZ26","teacher":"TEACH26","driver":"DRIVE26","student":"STAR26"}'
  ) RETURNING id INTO v_tour;

  -- ─── Agenda Days ──────────────────────────────────────────────────────────────

  -- ─── Day 1 — Jun 14 (Sunday): Travel Idaho Falls → Anaheim ────────────────────

  -- ─── Day 2 — Jun 15 (Monday): Disneyland Workshop ─────────────────────────────

  -- ─── Day 3 — Jun 16 (Tuesday): Long Beach Clinic, Hollywood, Medieval Times ────

  -- ─── Day 4 — Jun 17 (Wednesday): Disney California Adventure Performance ───────

  -- ─── Day 5 — Jun 18 (Thursday): Knott's Berry Farm Performance ────────────────

  -- ─── Day 6 — Jun 19 (Friday): Universal Studios STARS Performance ─────────────

  -- ─── Day 7 — Jun 20 (Saturday): Return Anaheim → Idaho Falls ──────────────────

  -- ─── Post-Trip placeholder ────────────────────────────────────────────────────

END $$;
